import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface WorldRegion {
  id: string;
  name: string;
  description: string;
  imageUrl: string;
  color: string;
}

export interface SpiritMessage {
  role: 'user' | 'spirit';
  text: string;
}

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import WorldSection from './components/WorldSection';
import SpiritWisdom from './components/SpiritWisdom';
import SocialSection from './components/SocialSection';
import Footer from './components/Footer';

const App: React.FC = () => {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <div className="min-h-screen sky-gradient selection:bg-blue-500/30">
      <Navbar isScrolled={scrolled} />

      <main>
        <section id="hero">
          <Hero />
        </section>

        <section id="world" className="py-24 px-6 md:px-12 lg:px-24">
          <WorldSection />
        </section>

        <section id="spirit" className="py-24 bg-black/20">
          <div className="max-w-4xl mx-auto px-6">
            <div className="text-center mb-16">
              <h2 className="text-4xl md:text-5xl font-cinzel text-blue-100 mb-4">Whispers of the Ancestors</h2>
              <p className="text-blue-300 text-lg">Seek guidance from the spirits of light. They have watched over these realms for aeons.</p>
            </div>
            <SpiritWisdom />
          </div>
        </section>

        <section id="social" className="py-24 px-6 md:px-12 lg:px-24">
          <SocialSection />
        </section>
      </main>

      <Footer />
    </div>
  );
};

export default App;

